namespace TicketClassifier.Models;

public sealed class EvaluationMetrics
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public Dictionary<string, PerClassMetrics> PerClass { get; set; } = new();
}

public sealed class PerClassMetrics
{
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class ModelTrainerService
{
    private readonly ILogger<ModelTrainerService> _logger;
    private readonly string _dataPath;
    private readonly string _modelPath;

    public ModelTrainerService(ILogger<ModelTrainerService> logger, IWebHostEnvironment env)
    {
        _logger = logger;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public EvaluationMetrics TrainAndEvaluate()
    {
        var mlContext = new MLContext(seed: 42);

        IDataView data = mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Combine Subject + Description text features with the numeric Priority feature
        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training ticket classification model...");
        ITransformer model = pipeline.Fit(split.TrainSet);

        _logger.LogInformation("Evaluating model on test set...");
        IDataView predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        _logger.LogInformation(
            "Macro accuracy: {MacroAccuracy:F4}, Micro accuracy: {MicroAccuracy:F4}, LogLoss: {LogLoss:F4}",
            metrics.MacroAccuracy, metrics.MicroAccuracy, metrics.LogLoss);

        // Log per-class metrics
        var confusionMatrix = metrics.ConfusionMatrix;
        var classNames = confusionMatrix.PerClassPrecision
            .Select((_, i) => confusionMatrix.PerClassPrecision.Count > i ? $"Class {i}" : "Unknown")
            .ToList();

        for (int i = 0; i < confusionMatrix.PerClassPrecision.Count; i++)
        {
            _logger.LogInformation(
                "  Class {Index}: Precision={Precision:F4}, Recall={Recall:F4}",
                i, confusionMatrix.PerClassPrecision[i], confusionMatrix.PerClassRecall[i]);
        }

        // Save trained model
        mlContext.Model.Save(model, split.TrainSet.Schema, _modelPath);
        _logger.LogInformation("Model saved to {ModelPath}", _modelPath);

        // Build response metrics
        var evalResult = new EvaluationMetrics
        {
            MacroAccuracy = metrics.MacroAccuracy,
            MicroAccuracy = metrics.MicroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction
        };

        // Map class indices back to category names from the label key
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        predictions.Schema["PredictedLabel"]
            .GetKeyValues(ref labelBuffer);
        var labels = labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();

        // If label extraction didn't work, fall back to known categories
        string[] categoryNames = labels.Length == confusionMatrix.PerClassPrecision.Count
            ? labels
            : ["Billing", "General", "Technical"];

        for (int i = 0; i < confusionMatrix.PerClassPrecision.Count; i++)
        {
            string name = i < categoryNames.Length ? categoryNames[i] : $"Class{i}";
            double precision = confusionMatrix.PerClassPrecision[i];
            double recall = confusionMatrix.PerClassRecall[i];
            evalResult.PerClass[name] = new PerClassMetrics
            {
                Precision = precision,
                Recall = recall,
                F1Score = precision + recall > 0
                    ? 2 * precision * recall / (precision + recall)
                    : 0
            };
        }

        return evalResult;
    }

    public string ModelPath => _modelPath;
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public sealed class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;

    public TicketsController(PredictionEnginePool<TicketInput, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    /// <summary>
    /// Predict the category for a support ticket.
    /// </summary>
    [HttpPost("classify")]
    public ActionResult<TicketResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        string[] categories = ["Billing", "General", "Technical"];
        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < prediction.Score.Length && i < categories.Length; i++)
        {
            confidence[categories[i]] = prediction.Score[i];
        }

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        });
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public sealed class ModelController : ControllerBase
{
    private readonly ModelTrainerService _trainer;

    public ModelController(ModelTrainerService trainer)
    {
        _trainer = trainer;
    }

    /// <summary>
    /// Retrain the model and return evaluation metrics.
    /// </summary>
    [HttpPost("train")]
    public ActionResult<EvaluationMetrics> Train()
    {
        var metrics = _trainer.TrainAndEvaluate();
        return Ok(metrics);
    }
}

